class Solution:
    def maxSideLength(self, mat, threshold: int) -> int:
        m, n = len(mat), len(mat[0])
        ps = [[0] * (n + 1) for _ in range(m + 1)]
        for r in range(1, m + 1):
            for c in range(1, n + 1):
                ps[r][c] = mat[r-1][c-1] + ps[r-1][c] + ps[r][c-1] - ps[r-1][c-1]
        def feasible(k):
            for r in range(k, m + 1):
                for c in range(k, n + 1):
                    if ps[r][c] - ps[r-k][c] - ps[r][c-k] + ps[r-k][c-k] <= threshold:
                        return True
            return False
        lo, hi = 0, min(m, n)
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

