var maxSideLength = function(mat, threshold) {
    const m = mat.length, n = mat[0].length;
    const ps = Array.from({length: m + 1}, () => new Array(n + 1).fill(0));
    for (let r = 1; r <= m; r++)
        for (let c = 1; c <= n; c++)
            ps[r][c] = mat[r-1][c-1] + ps[r-1][c] + ps[r][c-1] - ps[r-1][c-1];
    const feasible = (k) => {
        for (let r = k; r <= m; r++)
            for (let c = k; c <= n; c++)
                if (ps[r][c] - ps[r-k][c] - ps[r][c-k] + ps[r-k][c-k] <= threshold)
                    return true;
        return false;
    };
    let lo = 0, hi = Math.min(m, n);
    while (lo < hi) {
        const mid = (lo + hi + 1) >> 1;
        if (feasible(mid)) lo = mid; else hi = mid - 1;
    }
    return lo;
};
